"use client";

import { Handle } from "@xyflow/react";
import { memo } from "react";

import { cn } from "@/lib/utils";
import { resolveTheme } from "@/registry/thornberry/lib/node-themes";

import type { Node, NodeProps, Position } from "@xyflow/react";
import type { LucideIcon } from "lucide-react";
import type { CSSProperties, ReactNode } from "react";
import type {
  NodeTheme,
  NodeThemeKey,
} from "@/registry/thornberry/lib/node-themes";

/**
 * Standard node dimensions for consistent canvas layout. The width is an
 * even multiple of the default grid size for clean center alignment.
 */
export const NODE_WIDTH = 300;
export const NODE_MIN_HEIGHT = 120;

/** Connection handle configuration */
interface NodeHandleConfig {
  type: "source" | "target";
  position: Position;
  id?: string;
  className?: string;
  style?: CSSProperties;
}

/**
 * Node data shape consumed by the `base` node type. React Flow supplies
 * `selected` on the node props, so it is not part of the data payload.
 * Consumers add nodes as `{ type: "base", data: { theme, label, ... } }`.
 */
export interface BaseNodeData {
  /** Theme key or fully custom theme object */
  theme: NodeThemeKey | NodeTheme;
  /** Optional icon rendered in the header badge */
  icon?: LucideIcon;
  /** Node title */
  label: string;
  /** Optional secondary description under the label */
  description?: string;
  /** Optional badge text rendered in the header */
  badge?: string;
  /** Connection handles to render */
  handles?: NodeHandleConfig[];
  /** Optional body content */
  children?: ReactNode;
  /** Optional footer content */
  footer?: ReactNode;
  /** Click handler for the node */
  onClick?: () => void;
  /** Delete handler; when set, a delete button is shown on hover */
  onDelete?: () => void;
  // Index signature so the shape satisfies React Flow's `Record`-based node data
  [key: string]: unknown;
}

/**
 * Generic base node providing a consistent header (icon, label, optional
 * description and badge), optional body and footer, selection state, and
 * connection handles. It is a proper React Flow node component: content
 * comes from `data` and selection from props, so it can be registered
 * directly as a `nodeType` without an adapter. Styling is driven by a
 * semantic {@link NodeTheme}.
 */
export const BaseNode = memo(
  ({ data, selected }: NodeProps<Node<BaseNodeData>>) => {
    const {
      theme,
      icon: Icon,
      label,
      description,
      badge,
      handles = [],
      children,
      footer,
      onClick,
      onDelete,
    } = data;
    const t = resolveTheme(theme);

    return (
      <div
        className={cn(
          "group relative rounded-xl border px-4 py-3",
          onClick && "cursor-pointer",
          t.border,
          t.bg,
          t.glow,
          selected && "ring-2 ring-ring ring-offset-2",
        )}
        style={{ width: NODE_WIDTH, minHeight: NODE_MIN_HEIGHT }}
        role={onClick ? "button" : undefined}
        tabIndex={onClick ? 0 : undefined}
        onClick={onClick}
        onKeyDown={
          onClick
            ? (e) => {
                if (e.key === "Enter" || e.key === " ") {
                  e.preventDefault();
                  onClick();
                }
              }
            : undefined
        }
      >
        {onDelete && (
          <button
            type="button"
            aria-label="Delete node"
            className="absolute -top-3 -right-3 flex h-6 w-6 items-center justify-center rounded-full border bg-card text-destructive opacity-0 shadow-md transition-opacity group-hover:opacity-100"
            onClick={(e) => {
              e.stopPropagation();
              onDelete();
            }}
          >
            <span aria-hidden="true">x</span>
          </button>
        )}

        {/* Header */}
        <div className="flex min-w-0 items-center justify-between gap-3">
          <div className="flex min-w-0 flex-1 items-center gap-3">
            {Icon && (
              <div
                className={cn(
                  "flex h-10 w-10 shrink-0 items-center justify-center rounded-xl shadow-sm",
                  t.iconBg,
                )}
              >
                <Icon className={cn("h-5 w-5", t.iconText)} />
              </div>
            )}
            <div className="flex min-w-0 flex-1 flex-col overflow-hidden">
              <span className="truncate font-medium">{label}</span>
              {description && (
                <span className="truncate text-xs opacity-70">
                  {description}
                </span>
              )}
            </div>
          </div>
          {badge && (
            <span
              className={cn(
                "shrink-0 rounded-full px-2 py-0.5 text-xs",
                t.iconBg,
                t.iconText,
              )}
            >
              {badge}
            </span>
          )}
        </div>

        {/* Body */}
        {children && <div className="mt-3 space-y-2">{children}</div>}

        {/* Footer */}
        {footer && <div className="mt-3">{footer}</div>}

        {/* Handles */}
        {handles.map((handle, index) => (
          <Handle
            key={handle.id ?? `${handle.type}-${handle.position}-${index}`}
            type={handle.type}
            position={handle.position}
            id={handle.id}
            className={cn("h-3 w-3", handle.className ?? t.handleColor)}
            style={handle.style}
          />
        ))}
      </div>
    );
  },
);

BaseNode.displayName = "BaseNode";

import { clsx } from "clsx";
import { twMerge } from "tailwind-merge";

import type { ClassValue } from "clsx";

export const cn = (...inputs: ClassValue[]) => {
  return twMerge(clsx(inputs));
};

/**
 * Visual theme for a node, expressed as Tailwind utility class strings.
 *
 * Consumers either pick one of the semantic keys in {@link nodeThemes} or
 * pass a fully custom object of this shape.
 */
export interface NodeTheme {
  /** Border classes for the node container */
  border: string;
  /** Background classes for the node container */
  bg: string;
  /** Background classes for the icon badge */
  iconBg: string;
  /** Text/foreground classes for the icon */
  iconText: string;
  /** Accent text classes (labels, emphasis) */
  accent: string;
  /** Background classes applied to connection handles */
  handleColor: string;
  /** Optional box-shadow/glow classes */
  glow?: string;
}

/**
 * Small set of generic, semantic node themes driven by the design
 * system's CSS-variable tokens (card, primary, muted, destructive).
 *
 * `success` and `warning` are not part of the base token set, so they
 * fall back to fixed emerald/amber hues to keep their conventional
 * meaning.
 */
export const nodeThemes = {
  default: {
    border: "border-border",
    bg: "bg-card",
    iconBg: "bg-secondary",
    iconText: "text-secondary-foreground",
    accent: "text-foreground",
    handleColor: "!bg-muted-foreground",
  },
  accent: {
    border: "border-primary",
    bg: "bg-primary/10",
    iconBg: "bg-primary",
    iconText: "text-primary-foreground",
    accent: "text-primary",
    handleColor: "!bg-primary",
    glow: "shadow-[0_0_15px_rgba(59,130,246,0.15)]",
  },
  // success/warning have no design-system token; use fixed hues
  success: {
    border: "border-emerald-300/60 dark:border-emerald-600/40",
    bg: "bg-emerald-50 dark:bg-emerald-950",
    iconBg: "bg-emerald-600 dark:bg-emerald-500",
    iconText: "text-white",
    accent: "text-emerald-600 dark:text-emerald-400",
    handleColor: "!bg-emerald-500",
    glow: "shadow-[0_0_15px_rgba(16,185,129,0.15)]",
  },
  // success/warning have no design-system token; use fixed hues
  warning: {
    border: "border-amber-300/60 dark:border-amber-600/40",
    bg: "bg-amber-50 dark:bg-amber-950",
    iconBg: "bg-amber-500 dark:bg-amber-600",
    iconText: "text-white",
    accent: "text-amber-600 dark:text-amber-400",
    handleColor: "!bg-amber-500",
    glow: "shadow-[0_0_15px_rgba(245,158,11,0.15)]",
  },
  danger: {
    border: "border-destructive",
    bg: "bg-destructive/10",
    iconBg: "bg-destructive",
    iconText: "text-white",
    accent: "text-destructive",
    handleColor: "!bg-destructive",
    glow: "shadow-[0_0_15px_rgba(239,68,68,0.15)]",
  },
  muted: {
    border: "border-border",
    bg: "bg-muted",
    iconBg: "bg-muted-foreground",
    iconText: "text-background",
    accent: "text-muted-foreground",
    handleColor: "!bg-muted-foreground",
  },
} as const satisfies Record<string, NodeTheme>;

/** Union of the built-in semantic theme keys */
export type NodeThemeKey = keyof typeof nodeThemes;

/**
 * Resolve a theme input to a concrete {@link NodeTheme}.
 *
 * A string key is looked up in {@link nodeThemes}; a custom object is
 * returned unchanged.
 */
export const resolveTheme = (theme: NodeThemeKey | NodeTheme): NodeTheme =>
  typeof theme === "string" ? nodeThemes[theme] : theme;
